cd backend && python3 -c "
import ast, os, sys

# Known stdlib and project modules
skip = {'django','rest_framework','drf_spectacular','corsheaders','dj_database_url',
        'dotenv','celery','cryptography','nacl','httpx','requests','psycopg2','gunicorn',
        'qrcode','PIL','json','os','sys','re','datetime','pathlib','typing','uuid',
        'logging','hashlib','base64','hmac','time','io','enum','abc','math','random',
        'string','copy','itertools','functools','collections','threading','decimal',
        'traceback','inspect','importlib','dataclasses','contextlib','secrets','urllib',
        'http','email','html','xml','csv','zipfile','struct','binascii','codecs',
        'typing_extensions','asyncio','concurrent','multiprocessing','subprocess',
        'identity','organizations','common','dids','credentials','verification',
        'audit','trust_registry','admin_portal','accounts','national_id','did',
        'holder','issuer','verifier','notifications','oid4vci','apps','__future__'}

found = set()
for root, dirs, files in os.walk('apps'):
    for f in files:
        if not f.endswith('.py'): continue
        path = os.path.join(root, f)
        try:
            tree = ast.parse(open(path).read())
            for node in ast.walk(tree):
                if isinstance(node, ast.Import):
                    for alias in node.names:
                        top = alias.name.split('.')[0]
                        if top not in skip and not top.startswith('_'):
                            found.add(top)
                elif isinstance(node, ast.ImportFrom):
                    if node.level == 0 and node.module:
                        top = node.module.split('.')[0]
                        if top not in skip and not top.startswith('_'):
                            found.add(top)
        except: pass

print('\n'.join(sorted(found)))
" 2>&1

