"""
FederatedMemberService — calls an issuer organization's external member API
to verify that a person is an active member before issuing a credential.

Distinct exception hierarchy so callers can handle each failure mode differently
and produce clear, user-facing messages.
"""
from __future__ import annotations
import logging
import httpx
from audit.services import AuditService

logger = logging.getLogger(__name__)

TIMEOUT = 10  # seconds


# ── Exception hierarchy ────────────────────────────────────────────────────────

class FederatedVerificationError(Exception):
    """Base class — catch this to handle any federated verification failure."""


class ApiConfigNotFoundException(FederatedVerificationError):
    """No IssuerApiConfig exists for the organization."""


class ApiConfigNotTestedException(FederatedVerificationError):
    """API config exists but has never been successfully tested."""


class MemberNotEligibleException(FederatedVerificationError):
    """The member API confirmed the person is not eligible."""


class MemberApiTimeoutException(FederatedVerificationError):
    """The member API did not respond within the timeout."""


class MemberApiErrorException(FederatedVerificationError):
    """The member API returned a non-200 HTTP status code."""


class MemberApiInvalidResponseException(FederatedVerificationError):
    """The member API response could not be parsed as valid JSON."""


class MemberApiUnreachableException(FederatedVerificationError):
    """Could not connect to the member API at all."""


# ── Result types ───────────────────────────────────────────────────────────────

class MemberVerificationResult:
    def __init__(self, is_valid: bool, member_name: str, claims: dict):
        self.is_valid = is_valid
        self.member_name = member_name
        self.claims = claims
        # Keep legacy attribute for backward compatibility
        self.extra_claims = claims


class TestConnectionResult:
    def __init__(
        self,
        success: bool,
        response_body=None,
        error: str = '',
        fields_found: list = None,
        mapped_claims: dict = None,
    ):
        self.success = success
        self.response_body = response_body
        self.error = error
        self.fields_found = fields_found or []
        self.mapped_claims = mapped_claims or {}


# ── Service ────────────────────────────────────────────────────────────────────

class FederatedMemberService:

    @staticmethod
    def verify_member(
        organization, member_identifier: str, actor=None
    ) -> MemberVerificationResult:
        """
        Call the organization's member API and verify the member.
        Raises a subclass of FederatedVerificationError on any failure.
        """
        config = _get_config(organization)

        url = _build_url(config)
        headers = {config.api_key_header: config.api_key_value}
        payload = {config.request_id_field: member_identifier}

        try:
            response = httpx.post(url, json=payload, headers=headers, timeout=TIMEOUT)
        except httpx.TimeoutException:
            _log_failure(organization, member_identifier, 'api_timeout', actor)
            raise MemberApiTimeoutException(
                f"Your member database API did not respond within {TIMEOUT} seconds. "
                "Please check that the API server is running and accessible."
            )
        except httpx.ConnectError as exc:
            _log_failure(organization, member_identifier, 'api_unreachable', actor)
            raise MemberApiUnreachableException(
                f"Could not reach your member database API at {url}. "
                f"Please verify the URL is correct and the server is running. (Detail: {exc})"
            )
        except Exception as exc:
            _log_failure(organization, member_identifier, 'api_error', actor)
            raise MemberApiErrorException(f"Member API request failed: {exc}")

        if response.status_code != 200:
            _log_failure(organization, member_identifier, 'api_non_200', actor)
            raise MemberApiErrorException(
                f"Your member database API returned HTTP {response.status_code}. "
                f"Response: {response.text[:300]}"
            )

        try:
            data = response.json()
        except Exception:
            _log_failure(organization, member_identifier, 'invalid_response', actor)
            raise MemberApiInvalidResponseException(
                "Your member database API returned a response that is not valid JSON. "
                "Please check that your endpoint returns Content-Type: application/json."
            )

        eligibility_val = _resolve_dot_path(config.response_eligibility_field, data)
        is_eligible = _truthy(eligibility_val)

        if not is_eligible:
            _log_failure(organization, member_identifier, 'member_not_eligible', actor)
            reason = data.get('reason') or data.get('message') or (
                f"The person with identifier '{member_identifier}' is not eligible "
                f"according to {organization.name}'s database."
            )
            raise MemberNotEligibleException(reason)

        member_name = str(_resolve_dot_path(config.response_name_field, data) or '')

        claims = _apply_field_mappings(config.field_mappings or [], data)

        logger.info(
            "FederatedMemberService: verified member %s for org %s",
            member_identifier, organization.name
        )
        if actor:
            _audit(actor, organization, member_identifier, 'federated_member_verified')

        return MemberVerificationResult(is_valid=True, member_name=member_name, claims=claims)

    @staticmethod
    def test_connection(
        organization, test_member_identifier: str
    ) -> TestConnectionResult:
        """
        Same as verify_member but catches all exceptions and returns a structured result.
        Does NOT raise. Lets the caller see exactly what the API returned.
        """
        try:
            config = _get_config(organization)
        except ApiConfigNotFoundException as exc:
            return TestConnectionResult(success=False, error=str(exc))

        url = _build_url(config)
        headers = {config.api_key_header: config.api_key_value}
        payload = {config.request_id_field: test_member_identifier}

        try:
            response = httpx.post(url, json=payload, headers=headers, timeout=TIMEOUT)
        except httpx.TimeoutException:
            return TestConnectionResult(
                success=False,
                error=(
                    f"Connection timed out after {TIMEOUT} seconds. "
                    "Check that the URL is correct and your server is running."
                ),
            )
        except httpx.ConnectError as exc:
            return TestConnectionResult(
                success=False,
                error=(
                    f"Could not reach your API at {url}. "
                    "Check that the URL is correct and your server is running."
                ),
            )
        except Exception as exc:
            return TestConnectionResult(success=False, error=str(exc))

        if response.status_code == 401 or response.status_code == 403:
            return TestConnectionResult(
                success=False,
                error=(
                    "Your API rejected the platform's API key "
                    f"(HTTP {response.status_code}). "
                    "Check that the key matches what your server expects."
                ),
            )

        try:
            data = response.json()
        except Exception:
            return TestConnectionResult(
                success=False,
                error=(
                    "Your API returned an unexpected response format. "
                    "Check that your endpoint returns valid JSON."
                ),
            )

        eligibility_val = _resolve_dot_path(config.response_eligibility_field, data)
        is_eligible = _truthy(eligibility_val)

        if not is_eligible:
            reason = data.get('reason') or data.get('message') or 'Member not found in your system.'
            return TestConnectionResult(
                success=False,
                response_body=data,
                error=f"Member not found in your system. ({reason}) "
                      "This is expected if you used an ID that does not exist.",
                fields_found=_list_fields(data),
                mapped_claims=_apply_field_mappings(config.field_mappings or [], data),
            )

        fields_found = _list_fields(data)
        mapped_claims = _apply_field_mappings(config.field_mappings or [], data)

        return TestConnectionResult(
            success=True,
            response_body=data,
            fields_found=fields_found,
            mapped_claims=mapped_claims,
        )


# ── Utilities ──────────────────────────────────────────────────────────────────

def _get_config(organization):
    try:
        return organization.api_config
    except Exception:
        raise ApiConfigNotFoundException(
            "No member API has been configured for this organization. "
            "Please configure it in Member API Setup before issuing credentials."
        )


def _build_url(config) -> str:
    base = config.api_base_url.rstrip('/')
    endpoint = config.member_verify_endpoint
    if not endpoint.startswith('/'):
        endpoint = '/' + endpoint
    return base + endpoint


def _resolve_dot_path(path: str, data: dict):
    """
    Traverse a dot-notation path through a nested dict.
    Returns None gracefully if any key is missing or a value is not a dict.
    """
    if not path or not isinstance(data, dict):
        return None
    parts = path.split('.')
    current = data
    for part in parts:
        if not isinstance(current, dict):
            return None
        current = current.get(part)
        if current is None:
            return None
    return current


def _apply_field_mappings(field_mappings: list, data: dict) -> dict:
    """
    Apply the field_mappings array to extract credential claims from API response data.
    Each mapping: {response_path: str, credential_field: str}
    Returns a dict of {credential_field: value}.
    """
    claims = {}
    for mapping in field_mappings:
        response_path = mapping.get('response_path') or mapping.get('response_field', '')
        credential_field = mapping.get('credential_field') or mapping.get('claim_name', '')
        if response_path and credential_field:
            claims[credential_field] = _resolve_dot_path(response_path, data)
    return claims


def _list_fields(data: dict, prefix: str = '') -> list:
    """
    Recursively list all dot-notation paths in a response dict.
    """
    fields = []
    if not isinstance(data, dict):
        return fields
    for key, val in data.items():
        full_key = f"{prefix}.{key}" if prefix else key
        fields.append(full_key)
        if isinstance(val, dict):
            fields.extend(_list_fields(val, full_key))
    return fields


def _truthy(val) -> bool:
    if val is None:
        return False
    if isinstance(val, bool):
        return val
    if isinstance(val, str):
        return val.lower() in ('true', '1', 'yes', 'active', 'valid', 'eligible')
    if isinstance(val, (int, float)):
        return bool(val)
    return False


def _log_failure(organization, member_identifier: str, reason: str, actor=None):
    logger.warning(
        "FederatedMemberService: verification FAILED for member=%s org=%s reason=%s",
        member_identifier, organization.name, reason
    )
    if actor:
        _audit(actor, organization, member_identifier, 'federated_member_verification_failed',
               extra={'reason': reason})


def _audit(actor, organization, member_identifier: str, action: str, extra: dict = None):
    try:
        meta = {'member_identifier': member_identifier, 'org': str(organization.id)}
        if extra:
            meta.update(extra)
        AuditService.log(
            user=actor,
            action=action,
            entity_type='Organization',
            entity_id=organization.id,
            metadata=meta,
        )
    except Exception:
        pass

"""
Issuer API Config Views — federated member verification config
GET/POST /api/issuer/api-config/
POST     /api/issuer/api-config/test/
GET      /api/issuer/member-preview/
"""
from __future__ import annotations
from django.utils import timezone
from rest_framework.views import APIView
from rest_framework.response import Response
from rest_framework.permissions import IsAuthenticated
from organizations.models import OrganizationMember
from issuer.models import IssuerApiConfig


def _get_issuer_org(request):
    membership = OrganizationMember.objects.filter(
        user=request.user,
        role_in_org__in=['issuer_staff', 'manager'],
        is_active=True,
    ).select_related('organization').first()
    return membership.organization if membership else None


def _config_data(cfg: IssuerApiConfig) -> dict:
    mappings = cfg.field_mappings or []
    if isinstance(mappings, dict):
        mappings = [{'response_path': k, 'credential_field': v} for k, v in mappings.items()]
    return {
        'id': str(cfg.id),
        'api_base_url': cfg.api_base_url,
        'member_verify_endpoint': cfg.member_verify_endpoint,
        'api_key_header': cfg.api_key_header,
        'api_key_value': cfg.masked_api_key(),
        'request_id_field': cfg.request_id_field,
        'response_eligibility_field': cfg.response_eligibility_field,
        'response_name_field': cfg.response_name_field,
        'field_mappings': mappings,
        'is_active': cfg.is_active,
        'last_tested_at': cfg.last_tested_at.isoformat() if cfg.last_tested_at else None,
        'last_test_status': cfg.last_test_status,
        'last_test_error': cfg.last_test_error,
    }


class IssuerApiConfigView(APIView):
    permission_classes = [IsAuthenticated]

    def get(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)
        try:
            cfg = IssuerApiConfig.objects.get(organization=org)
            return Response(_config_data(cfg))
        except IssuerApiConfig.DoesNotExist:
            return Response(None, status=200)

    def post(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        data = request.data

        # Normalize field_mappings — accept both list of {response_path, credential_field}
        # and legacy list of {response_field, claim_name}
        raw_mappings = data.get('field_mappings') or data.get('response_extra_fields', [])
        normalized_mappings = []
        if isinstance(raw_mappings, list):
            for row in raw_mappings:
                rp = row.get('response_path') or row.get('response_field', '')
                cf = row.get('credential_field') or row.get('claim_name', '')
                if rp and cf:
                    normalized_mappings.append({'response_path': rp, 'credential_field': cf})
        elif isinstance(raw_mappings, dict):
            for k, v in raw_mappings.items():
                normalized_mappings.append({'response_path': k, 'credential_field': v})

        api_key_val = data.get('api_key_value', '')

        cfg, created = IssuerApiConfig.objects.get_or_create(
            organization=org,
            defaults={'api_key_value': api_key_val or ''}
        )

        cfg.api_base_url = data.get('api_base_url', cfg.api_base_url)
        cfg.member_verify_endpoint = data.get('member_verify_endpoint', cfg.member_verify_endpoint)
        cfg.api_key_header = data.get('api_key_header', cfg.api_key_header)
        if api_key_val and not api_key_val.startswith('****'):
            cfg.api_key_value = api_key_val
        cfg.request_id_field = data.get('request_id_field', cfg.request_id_field)
        cfg.response_eligibility_field = (
            data.get('response_eligibility_field')
            or data.get('response_status_field')
            or cfg.response_eligibility_field
        )
        cfg.response_name_field = data.get('response_name_field', cfg.response_name_field)
        cfg.field_mappings = normalized_mappings
        cfg.is_active = data.get('is_active', cfg.is_active)
        cfg.save()

        from audit.services import AuditService
        AuditService.log(
            user=request.user,
            action='api_config_updated',
            entity_type='IssuerApiConfig',
            entity_id=cfg.id,
        )

        return Response(_config_data(cfg), status=201 if created else 200)


class IssuerApiConfigTestView(APIView):
    permission_classes = [IsAuthenticated]

    def post(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        try:
            cfg = IssuerApiConfig.objects.get(organization=org)
        except IssuerApiConfig.DoesNotExist:
            return Response(
                {'error': 'API configuration not found. Please save a configuration first.'},
                status=404
            )

        test_member_id = (request.data.get('test_member_id') or '').strip()
        if not test_member_id:
            return Response({'error': 'test_member_id is required.'}, status=400)

        from issuer.services.federated_member_service import FederatedMemberService
        result = FederatedMemberService.test_connection(org, test_member_id)

        cfg.last_tested_at = timezone.now()
        cfg.last_test_status = (
            IssuerApiConfig.TEST_STATUS_SUCCESS if result.success
            else IssuerApiConfig.TEST_STATUS_FAILED
        )
        cfg.last_test_error = result.error or ''
        cfg.save(update_fields=['last_tested_at', 'last_test_status', 'last_test_error', 'updated_at'])

        from audit.services import AuditService
        AuditService.log(
            user=request.user,
            action='api_config_tested',
            entity_type='IssuerApiConfig',
            entity_id=cfg.id,
            metadata={'success': result.success, 'test_member_id': test_member_id},
        )

        mapped_claims_table = []
        for mapping in (cfg.field_mappings or []):
            rp = mapping.get('response_path', '')
            cf = mapping.get('credential_field', '')
            val = result.mapped_claims.get(cf)
            mapped_claims_table.append({
                'response_path': rp,
                'credential_field': cf,
                'value_found': val,
                'resolved': val is not None,
            })

        return Response({
            'success': result.success,
            'error': result.error or None,
            'raw_response': result.response_body,
            'fields_found': result.fields_found,
            'mapped_claims': result.mapped_claims,
            'mapped_claims_table': mapped_claims_table,
            'last_test_status': cfg.last_test_status,
        })


class MemberPreviewView(APIView):
    """GET /api/issuer/member-preview/?member_identifier=xxx"""
    permission_classes = [IsAuthenticated]

    def get(self, request):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)

        member_identifier = request.query_params.get('member_identifier', '').strip()
        if not member_identifier:
            return Response({'error': 'member_identifier is required.'}, status=400)

        from issuer.services.federated_member_service import (
            FederatedMemberService, FederatedVerificationError,
            MemberApiUnreachableException, MemberApiTimeoutException,
            MemberNotEligibleException, MemberApiErrorException,
            MemberApiInvalidResponseException,
        )

        try:
            result = FederatedMemberService.verify_member(org, member_identifier, actor=request.user)
            return Response({
                'found': True,
                'member_name': result.member_name,
                'extra_claims': result.claims,
                'claims': result.claims,
                'member_identifier': member_identifier,
            })
        except MemberApiUnreachableException as e:
            return Response({'found': False, 'error': str(e), 'error_type': 'unreachable'}, status=400)
        except MemberApiTimeoutException as e:
            return Response({'found': False, 'error': str(e), 'error_type': 'timeout'}, status=400)
        except MemberNotEligibleException as e:
            return Response({'found': False, 'error': str(e), 'error_type': 'not_eligible'}, status=400)
        except MemberApiInvalidResponseException as e:
            return Response({'found': False, 'error': str(e), 'error_type': 'invalid_response'}, status=400)
        except FederatedVerificationError as e:
            return Response({'found': False, 'error': str(e), 'error_type': 'general'}, status=400)

"""
Admin views for IssuerRegistration approval/rejection flow.

GET  /api/admin/organizations/pending/           — list submitted registrations
GET  /api/admin/organizations/pending/{id}/documents/ — documents for one registration
POST /api/admin/organizations/{id}/approve/      — approve and create Org+User+DID
POST /api/admin/organizations/{id}/reject/       — reject with reason
"""
from __future__ import annotations
import secrets
import string
import logging

from django.utils import timezone
from rest_framework.views import APIView
from rest_framework.response import Response
from rest_framework.permissions import IsAuthenticated

from identity.permissions import IsAdmin
from organizations.models.issuer_registration import IssuerRegistration, IssuerRegDocument
from common.email_service import EmailService

logger = logging.getLogger(__name__)


def _reg_data(reg: IssuerRegistration) -> dict:
    org_type_name = reg.organization_type.name if reg.organization_type else None
    return {
        'id': str(reg.id),
        'email': reg.email,
        'organization_name': reg.organization_name,
        'organization_type': org_type_name,
        'address': reg.address,
        'phone': reg.phone,
        'website': reg.website,
        'contact_person_name': reg.contact_person_name,
        'contact_person_email': reg.contact_person_email,
        'use_case_description': reg.use_case_description,
        'intended_credential_types': reg.intended_credential_types,
        'status': reg.status,
        'registration_step': reg.registration_step,
        'submitted_at': reg.submitted_at.isoformat() if reg.submitted_at else None,
        'reviewed_at': reg.reviewed_at.isoformat() if reg.reviewed_at else None,
        'rejection_reason': reg.rejection_reason,
        'created_at': reg.created_at.isoformat(),
        'document_count': reg.documents.count(),
    }


def _doc_data(doc: IssuerRegDocument, request=None) -> dict:
    try:
        url = request.build_absolute_uri(doc.file.url) if request and doc.file else None
    except Exception:
        url = None
    return {
        'id': str(doc.id),
        'document_type': doc.document_type,
        'document_type_display': doc.get_document_type_display(),
        'file_name': doc.file_name,
        'uploaded_at': doc.uploaded_at.isoformat(),
        'verified': doc.verified,
        'download_url': url,
    }


class PendingRegistrationsView(APIView):
    """GET /api/admin/organizations/pending/"""
    permission_classes = [IsAuthenticated, IsAdmin]

    def get(self, request):
        regs = IssuerRegistration.objects.filter(
            status__in=['submitted', 'under_review']
        ).order_by('-submitted_at')
        return Response({
            'count': regs.count(),
            'results': [_reg_data(r) for r in regs],
        })


class RegistrationDocumentsView(APIView):
    """GET /api/admin/organizations/pending/{registration_id}/documents/"""
    permission_classes = [IsAuthenticated, IsAdmin]

    def get(self, request, registration_id):
        try:
            reg = IssuerRegistration.objects.get(id=registration_id)
        except IssuerRegistration.DoesNotExist:
            return Response({'error': 'Registration not found.'}, status=404)
        docs = reg.documents.all()
        return Response([_doc_data(d, request) for d in docs])


def _generate_temp_password(length=16) -> str:
    alphabet = string.ascii_letters + string.digits + '!@#$%'
    return ''.join(secrets.choice(alphabet) for _ in range(length))


class ApproveRegistrationView(APIView):
    """POST /api/admin/organizations/{registration_id}/approve/"""
    permission_classes = [IsAuthenticated, IsAdmin]

    def post(self, request, registration_id):
        try:
            reg = IssuerRegistration.objects.get(id=registration_id)
        except IssuerRegistration.DoesNotExist:
            return Response({'error': 'Registration not found.'}, status=404)

        if reg.status == 'approved':
            return Response({'error': 'Registration is already approved.'}, status=400)

        if reg.status not in ('submitted', 'under_review'):
            return Response(
                {'error': f'Cannot approve a registration with status "{reg.status}".'},
                status=400
            )

        try:
            result = _create_org_and_user(reg, request.user)
        except Exception as exc:
            logger.exception("Error approving registration %s: %s", registration_id, exc)
            return Response({'error': f'Approval failed: {exc}'}, status=500)

        reg.status = 'approved'
        reg.reviewed_at = timezone.now()
        reg.save(update_fields=['status', 'reviewed_at', 'updated_at'])

        try:
            EmailService.send(
                subject=f'Welcome to CredWallet — {reg.organization_name} Account Approved',
                message=(
                    f'Dear {reg.contact_person_name},\n\n'
                    f'Your organization "{reg.organization_name}" has been approved on the CredWallet platform.\n\n'
                    f'Your login credentials:\n'
                    f'  Email: {reg.email}\n'
                    f'  Temporary Password: {result["temp_password"]}\n\n'
                    f'Please log in and change your password immediately.\n\n'
                    f'Best regards,\nThe CredWallet Team'
                ),
                recipient_list=[reg.email],
            )
        except Exception:
            pass

        from audit.services import AuditService
        AuditService.log(
            user=request.user,
            action='registration_approved',
            entity_type='IssuerRegistration',
            entity_id=reg.id,
            metadata={'organization_name': reg.organization_name, 'org_id': str(result['org_id'])},
        )

        return Response({
            'message': f'Organization "{reg.organization_name}" approved successfully.',
            'organization_id': str(result['org_id']),
            'user_created': True,
        })


class RejectRegistrationView(APIView):
    """POST /api/admin/organizations/{registration_id}/reject/"""
    permission_classes = [IsAuthenticated, IsAdmin]

    def post(self, request, registration_id):
        try:
            reg = IssuerRegistration.objects.get(id=registration_id)
        except IssuerRegistration.DoesNotExist:
            return Response({'error': 'Registration not found.'}, status=404)

        if reg.status == 'rejected':
            return Response({'error': 'Registration is already rejected.'}, status=400)

        reason = (request.data.get('reason') or '').strip()
        if not reason:
            return Response({'error': 'A rejection reason is required.'}, status=400)

        reg.status = 'rejected'
        reg.rejection_reason = reason
        reg.reviewed_at = timezone.now()
        reg.save(update_fields=['status', 'rejection_reason', 'reviewed_at', 'updated_at'])

        try:
            EmailService.send(
                subject=f'CredWallet Registration Update — {reg.organization_name}',
                message=(
                    f'Dear {reg.contact_person_name or reg.email},\n\n'
                    f'We have reviewed your registration application for "{reg.organization_name}".\n\n'
                    f'Unfortunately, we are unable to approve your application at this time.\n\n'
                    f'Reason: {reason}\n\n'
                    f'If you believe this decision was made in error, please contact our support team.\n\n'
                    f'Best regards,\nThe CredWallet Team'
                ),
                recipient_list=[reg.email],
            )
        except Exception:
            pass

        from audit.services import AuditService
        AuditService.log(
            user=request.user,
            action='registration_rejected',
            entity_type='IssuerRegistration',
            entity_id=reg.id,
            metadata={'reason': reason},
        )

        return Response({'message': 'Registration rejected.', 'reason': reason})


def _create_org_and_user(reg: IssuerRegistration, admin_user) -> dict:
    from django.contrib.auth import get_user_model
    from django.contrib.auth.hashers import make_password
    from organizations.models import Organization, OrganizationMember

    User = get_user_model()

    # Create or get Organization
    org, org_created = Organization.objects.get_or_create(
        name=reg.organization_name,
        defaults={
            'type': reg.organization_type,
            'address': reg.address or '',
            'phone': reg.phone or '',
            'website': reg.website or '',
            'contact_email': reg.contact_person_email or reg.email,
            'status': 'active',
        }
    )
    if not org_created:
        org.status = 'active'
        org.save(update_fields=['status'])

    # Generate temp password
    temp_password = _generate_temp_password()

    # Create or get User with issuer role
    user, user_created = User.objects.get_or_create(
        email=reg.email,
        defaults={
            'first_name': reg.contact_person_name.split()[0] if reg.contact_person_name else '',
            'last_name': ' '.join(reg.contact_person_name.split()[1:]) if reg.contact_person_name else '',
            'role': 'issuer',
            'is_active': True,
            'password': make_password(temp_password),
        }
    )
    if not user_created:
        user.role = 'issuer'
        user.is_active = True
        user.save(update_fields=['role', 'is_active'])

    # Link user to organization
    OrganizationMember.objects.get_or_create(
        user=user,
        organization=org,
        defaults={'role_in_org': 'manager', 'is_active': True}
    )

    # Try to create DID for the organization
    try:
        from dids.services import DIDGenerationService
        if not org.organization_did:
            did_service = DIDGenerationService()
            did_service.create_for_organization(org, created_by=admin_user)
    except Exception as exc:
        logger.warning("Could not create DID for org %s: %s", org.id, exc)

    return {
        'org_id': org.id,
        'user_id': user.id,
        'temp_password': temp_password,
        'org_created': org_created,
        'user_created': user_created,
    }

