from __future__ import annotations
from rest_framework.views import APIView
from rest_framework.response import Response
from rest_framework.permissions import AllowAny

INTEGRATION_GUIDE = {
    'title': 'Member Verification API Integration Guide',
    'version': '1.0',
    'overview': (
        'The CredWallet platform calls your organization\'s Member Verification API '
        'every time a credential is issued. Your API must confirm that the person is '
