        },
        'response': {
            'content_type': 'application/json',
            'success_example': {
                'is_eligible': True,
                'member': {
                    'full_name': 'Amara Osei',
                    'student_id': 'STU-2024-001',
                    'programme': 'Computer Science',
                    'year': 3,
                    'status': 'active',
