        'header_example': 'X-API-Key: <your-secret-key>',
        'recommendation': 'Use a random 32+ character string as your API key.',
    },
    'field_mapping': {
        'description': (
            'You configure dot-notation paths in the CredWallet dashboard to map '
            'fields from your API response to credential claims. '
            'For example, "member.full_name" maps to the nested field.'
        ),
        'eligibility_field': (
            'A dot-notation path (e.g. "is_eligible") to a boolean field that '
            'indicates whether the member is eligible for a credential.'
        ),
        'name_field': (
            'A dot-notation path (e.g. "member.full_name") to the member\'s display name.'
        ),
        'extra_fields': (
