    'implementation_examples': {
        'node_express': '''const express = require('express');
const app = express();
app.use(express.json());

const members = {
  'NID-1234567890': { full_name: 'Amara Osei', student_id: 'STU-001', status: 'active' },
};

app.post('/api/members/verify', (req, res) => {
  const apiKey = req.headers['x-api-key'];
  if (apiKey !== process.env.API_KEY) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  const id = req.body.member_id;
  const member = members[id];
  if (!member || member.status !== 'active') {
    return res.json({ is_eligible: false, reason: 'Member not found or inactive.' });
  }
  return res.json({ is_eligible: true, member });
});

app.listen(3000);''',
