import os

app = Flask(__name__)

members = {
    'NID-1234567890': {'full_name': 'Amara Osei', 'student_id': 'STU-001', 'status': 'active'},
}

@app.route('/api/members/verify', methods=['POST'])
def verify_member():
    if request.headers.get('X-API-Key') != os.environ['API_KEY']:
        return jsonify({'error': 'Unauthorized'}), 401
    member_id = request.json.get('member_id')
    member = members.get(member_id)
    if not member or member['status'] != 'active':
        return jsonify({'is_eligible': False, 'reason': 'Member not found or inactive.'})
    return jsonify({'is_eligible': True, 'member': member})''',
