class IssuerTemplateApiFieldPreviewView(APIView):
    """
    GET /api/issuer/templates/{id}/api-field-preview/
    Tests each member_api field's dot-notation path against the last test response.
    Returns which paths resolve successfully and what values they'd produce.
    """
    permission_classes = [IsAuthenticated]

    def get(self, request, pk):
        org = _get_issuer_org(request)
        if not org:
            return Response({'error': 'Not associated with an issuer organization.'}, status=403)
        t = get_object_or_404(IssuanceTemplate, id=pk, organization=org)

        # Get the API config to check last test response
        try:
            from issuer.models import IssuerApiConfig
            cfg = IssuerApiConfig.objects.get(organization=org)
        except Exception:
            return Response({'error': 'No member API configured yet.'}, status=400)

        if cfg.last_test_status != IssuerApiConfig.TEST_STATUS_SUCCESS:
            return Response({
                'error': 'Run a successful API connection test first so we can preview field paths.',
                'last_test_status': cfg.last_test_status,
            }, status=400)

        # Parse fields that use member_api source
        api_fields = [
            f for f in (t.fields or [])
            if f.get('source') == 'member_api'
        ]

        preview = []
        for field in api_fields:
            path = field.get('source_field') or field.get('api_response_path') or ''
            preview.append({
                'field_name': field.get('name'),
                'field_label': field.get('label', field.get('name')),
                'api_response_path': path,
                'note': (
                    'No API response path configured. Set one in the template editor.'
                    if not path else
                    'Path is configured. Run a connection test with a real member ID to verify.'
                ),
            })

        return Response({
            'template_name': t.name,
            'api_fields': preview,
            'api_config_status': cfg.last_test_status,
            'last_tested_at': cfg.last_tested_at.isoformat() if cfg.last_tested_at else None,
        })

