import { useState, useEffect } from 'react';
import { Outlet, Link } from 'react-router-dom';
import {
  LayoutDashboard, BadgeCheck, FileText, Send,
  ClipboardList, BarChart2, Bell, Settings, Plug,
  AlertTriangle, Clock, XCircle, CheckCircle2,
} from 'lucide-react';
import Sidebar from '../components/common/Sidebar';
import Topbar from '../components/common/Topbar';
import { getOrganization, getApiConfig } from '../api/issuer';

const navItems = [
  { to: '/issuer/dashboard', label: 'Dashboard', icon: LayoutDashboard, end: true },
  { to: '/issuer/credential-types', label: 'Credential Types', icon: BadgeCheck },
  { to: '/issuer/templates', label: 'Templates', icon: FileText },
  { to: '/issuer/issue', label: 'Issue Credential', icon: Send },
  { to: '/issuer/issue/bulk', label: 'Bulk Issuance', icon: Send },
  { to: '/issuer/issued', label: 'Issued Credentials', icon: BadgeCheck },
  { to: '/issuer/requests', label: 'Holder Requests', icon: ClipboardList },
  { to: '/issuer/analytics', label: 'Analytics', icon: BarChart2 },
  { to: '/issuer/api-config', label: 'API Config', icon: Plug },
  { to: '/issuer/notifications', label: 'Notifications', icon: Bell },
  { to: '/issuer/settings', label: 'Settings', icon: Settings },
];

function StatusBanner({ orgStatus, apiStatus }) {
  if (orgStatus === 'pending' || orgStatus === 'under_review') {
    return (
      <div className="bg-yellow-50 dark:bg-yellow-900/20 border-b border-yellow-200 dark:border-yellow-700 px-4 py-2 flex items-center gap-2 text-sm text-yellow-800 dark:text-yellow-200">
        <Clock className="h-4 w-4 flex-shrink-0" />
        <span>
          Your organization is <strong>pending approval</strong>. Credential issuance is disabled until approved by the platform administrators.
        </span>
      </div>
    );
  }

  if (orgStatus === 'suspended') {
    return (
      <div className="bg-red-50 dark:bg-red-900/20 border-b border-red-200 dark:border-red-700 px-4 py-2 flex items-center gap-2 text-sm text-red-800 dark:text-red-200">
        <XCircle className="h-4 w-4 flex-shrink-0" />
        <span>
          Your organization account has been <strong>suspended</strong>. Contact support for assistance.
        </span>
      </div>
    );
  }

  if (!apiStatus || apiStatus === 'not_configured') {
    return (
      <div className="bg-orange-50 dark:bg-orange-900/20 border-b border-orange-200 dark:border-orange-700 px-4 py-2 flex items-center gap-2 text-sm text-orange-800 dark:text-orange-200">
        <Plug className="h-4 w-4 flex-shrink-0" />
        <span>
          Member API not configured.{' '}
          <Link to="/issuer/api-config" className="underline font-medium">
            Set it up now
          </Link>{' '}
          to enable credential issuance.
        </span>
      </div>
    );
  }

  if (apiStatus === 'untested') {
    return (
      <div className="bg-orange-50 dark:bg-orange-900/20 border-b border-orange-200 dark:border-orange-700 px-4 py-2 flex items-center gap-2 text-sm text-orange-800 dark:text-orange-200">
        <AlertTriangle className="h-4 w-4 flex-shrink-0" />
        <span>
          Member API is configured but <strong>not yet tested</strong>.{' '}
          <Link to="/issuer/api-config" className="underline font-medium">
            Run a connection test
          </Link>{' '}
          to verify it works.
        </span>
      </div>
    );
  }

  if (apiStatus === 'error') {
    return (
      <div className="bg-red-50 dark:bg-red-900/20 border-b border-red-200 dark:border-red-700 px-4 py-2 flex items-center gap-2 text-sm text-red-800 dark:text-red-200">
        <XCircle className="h-4 w-4 flex-shrink-0" />
        <span>
          Member API connection <strong>test failed</strong>.{' '}
          <Link to="/issuer/api-config" className="underline font-medium">
            Review your configuration
          </Link>.
        </span>
      </div>
    );
  }

  return null;
}

export default function IssuerLayout() {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [orgStatus, setOrgStatus] = useState(null);
  const [apiStatus, setApiStatus] = useState(null);

  useEffect(() => {
    getOrganization()
      .then((r) => setOrgStatus(r.data?.status || 'active'))
      .catch(() => setOrgStatus('active'));

    getApiConfig()
      .then((r) => {
        if (!r.data) {
          setApiStatus('not_configured');
        } else {
          setApiStatus(r.data.last_test_status || 'untested');
        }
      })
      .catch(() => setApiStatus('not_configured'));
  }, []);

  return (
    <div className="flex h-screen overflow-hidden bg-background">
      {sidebarOpen && (
        <div className="fixed inset-0 z-30 bg-black/50 lg:hidden" onClick={() => setSidebarOpen(false)} />
      )}
      <div className={`fixed inset-y-0 left-0 z-40 lg:static lg:z-auto transition-transform duration-200 ${sidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}`}>
        <Sidebar navItems={navItems} logo="Issuer Portal" onClose={() => setSidebarOpen(false)} />
      </div>
      <div className="flex flex-1 flex-col overflow-hidden">
        <Topbar onMenuClick={() => setSidebarOpen(true)} title="Issuer Portal" />
        <StatusBanner orgStatus={orgStatus} apiStatus={apiStatus} />
        <main className="flex-1 overflow-y-auto p-4 lg:p-6">
          <Outlet />
        </main>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import {
  BadgeCheck, FileText, Send, ClipboardList,
  AlertTriangle, Users, Plug, Clock, CheckCircle2, XCircle,
} from 'lucide-react';
import { getIssuerDashboard, getIssuedCredentials } from '../../api/issuer';
import { StatusBadge } from '../../components/common/Badge';
import { CardSkeleton } from '../../components/common/SkeletonLoader';
import { formatDate } from '../../utils/formatDate';

function ApiStatusIcon({ status }) {
  if (status === 'connected') return <CheckCircle2 className="h-4 w-4 text-green-500" />;
  if (status === 'error') return <XCircle className="h-4 w-4 text-red-500" />;
  if (status === 'untested') return <AlertTriangle className="h-4 w-4 text-orange-400" />;
  return <Plug className="h-4 w-4 text-muted-foreground" />;
}

function ApiStatusLabel({ status }) {
  const map = {
    connected: 'Connected',
    error: 'Error',
    untested: 'Untested',
    disabled: 'Disabled',
    not_configured: 'Not Set',
  };
  return <span>{map[status] || 'Not Set'}</span>;
}

export default function IssuerDashboard() {
  const [stats, setStats] = useState(null);
  const [recent, setRecent] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      getIssuerDashboard(),
      getIssuedCredentials({ page_size: 5 }),
    ]).then(([dash, creds]) => {
      setStats(dash.data);
      setRecent(creds.data?.results || creds.data || []);
    }).catch(() => {}).finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="space-y-4"><CardSkeleton /><CardSkeleton /></div>;

  const apiStatus = stats?.api_config_status || 'not_configured';

  const statCards = [
    {
      label: 'Total Issued',
      value: stats?.total_issued ?? 0,
      icon: BadgeCheck,
      color: 'text-blue-600',
      bg: 'bg-blue-50 dark:bg-blue-900/20',
      href: '/issuer/issued',
    },
    {
      label: 'Active',
      value: stats?.active_count ?? 0,
      icon: CheckCircle2,
      color: 'text-green-600',
      bg: 'bg-green-50 dark:bg-green-900/20',
      href: '/issuer/issued?status=active',
    },
    {
      label: 'Revoked',
      value: stats?.revoked_count ?? 0,
      icon: AlertTriangle,
      color: 'text-red-500',
      bg: 'bg-red-50 dark:bg-red-900/20',
      href: '/issuer/issued?status=revoked',
    },
    {
      label: 'Pending Requests',
      value: stats?.pending_requests_count ?? 0,
      icon: ClipboardList,
      color: 'text-yellow-600',
      bg: 'bg-yellow-50 dark:bg-yellow-900/20',
      href: '/issuer/requests',
    },
    {
      label: 'Awaiting Wallet',
      value: stats?.pending_delivery_count ?? stats?.pending_holder_registrations_count ?? 0,
      icon: Users,
      color: 'text-orange-500',
      bg: 'bg-orange-50 dark:bg-orange-900/20',
      href: '/issuer/pending-credentials',
      tooltip: 'Credentials ready but holder has not yet registered a wallet',
    },
    {
      label: 'Member API',
      value: null,
      icon: Plug,
      color: apiStatus === 'connected' ? 'text-green-600' : apiStatus === 'error' ? 'text-red-500' : 'text-orange-500',
      bg: apiStatus === 'connected' ? 'bg-green-50 dark:bg-green-900/20' : apiStatus === 'error' ? 'bg-red-50 dark:bg-red-900/20' : 'bg-orange-50 dark:bg-orange-900/20',
      href: '/issuer/api-config',
      customValue: <ApiStatusLabel status={apiStatus} />,
      customIcon: <ApiStatusIcon status={apiStatus} />,
    },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground">Issuer Dashboard</h1>
          <p className="text-muted-foreground text-sm mt-1">Overview of your credential issuance activity.</p>
        </div>
        <Link to="/issuer/issue">
          <button className="btn-primary text-sm px-4 py-2 rounded-lg flex items-center gap-2">
            <Send className="h-4 w-4" /> Issue Credential
          </button>
        </Link>
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-3 xl:grid-cols-6 gap-4">
        {statCards.map((s) => (
          <Link key={s.label} to={s.href} className="card p-4 hover:shadow-md transition-shadow" title={s.tooltip}>
            <div className={`inline-flex p-2 rounded-lg ${s.bg} mb-3`}>
              {s.customIcon || <s.icon className={`h-4 w-4 ${s.color}`} />}
            </div>
            <p className={`text-xl font-bold ${s.color}`}>
              {s.customValue !== undefined ? s.customValue : s.value}
            </p>
            <p className="text-xs text-muted-foreground mt-0.5">{s.label}</p>
          </Link>
        ))}
      </div>

      {apiStatus !== 'connected' && (
        <div className={`card border p-4 ${apiStatus === 'error' ? 'border-red-200 dark:border-red-700 bg-red-50/50 dark:bg-red-900/10' : 'border-orange-200 dark:border-orange-700 bg-orange-50/50 dark:bg-orange-900/10'}`}>
          <div className="flex items-start gap-3">
            <Plug className={`h-5 w-5 mt-0.5 ${apiStatus === 'error' ? 'text-red-600' : 'text-orange-600'}`} />
            <div>
              <p className={`text-sm font-medium ${apiStatus === 'error' ? 'text-red-800 dark:text-red-200' : 'text-orange-800 dark:text-orange-200'}`}>
                {apiStatus === 'error' ? 'Member API connection test failed' :
                 apiStatus === 'untested' ? 'Member API not yet tested' :
                 'Member API not configured'}
              </p>
              <p className={`text-xs mt-0.5 ${apiStatus === 'error' ? 'text-red-700 dark:text-red-300' : 'text-orange-700 dark:text-orange-300'}`}>
                {apiStatus === 'error'
                  ? 'Credentials cannot be issued until the API connection is working.'
                  : 'Configure and test your organization\'s member verification API to enable credential issuance.'}
              </p>
              <Link to="/issuer/api-config" className={`text-xs underline mt-1 inline-block ${apiStatus === 'error' ? 'text-red-700 dark:text-red-300' : 'text-orange-700 dark:text-orange-300'}`}>
                {apiStatus === 'error' ? 'Review configuration →' : 'Set up API config →'}
              </Link>
            </div>
          </div>
        </div>
      )}

      <div className="card p-6">
        <div className="flex items-center justify-between mb-4">
          <h2 className="font-semibold text-foreground">Recent Credentials</h2>
          <Link to="/issuer/issued" className="text-sm text-primary hover:underline">View all →</Link>
        </div>
        {recent.length === 0 ? (
          <div className="text-center py-8">
            <BadgeCheck className="h-10 w-10 text-muted-foreground/30 mx-auto mb-2" />
            <p className="text-sm text-muted-foreground">No credentials issued yet.</p>
            <Link to="/issuer/issue" className="text-sm text-primary hover:underline mt-1 inline-block">
              Issue your first credential →
            </Link>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="text-left text-xs text-muted-foreground border-b border-border">
                  <th className="pb-2 pr-4 font-medium">Recipient</th>
                  <th className="pb-2 pr-4 font-medium">Type</th>
                  <th className="pb-2 pr-4 font-medium">Status</th>
                  <th className="pb-2 font-medium">Issued</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {recent.map((c) => (
                  <tr key={c.id}>
                    <td className="py-2 pr-4 font-medium">{c.holder_name || '—'}</td>
                    <td className="py-2 pr-4 text-muted-foreground">{c.credential_type || '—'}</td>
                    <td className="py-2 pr-4"><StatusBadge status={c.status} /></td>
                    <td className="py-2 text-muted-foreground">{formatDate(c.issued_at)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

