export const removeOrgMember = (userId) => api.delete(`/issuer/organization/members/${userId}/`);

// ─── API Configuration (Federated Member Verification) ────────────────────
export const getApiConfig = () => api.get('/issuer/api-config/');
export const saveApiConfig = (data) => api.post('/issuer/api-config/', data);
export const testApiConfig = (data) => api.post('/issuer/api-config/test/', data);
