export const activateCredentialType = (id) => api.post(`/issuer/credential-types/${id}/activate/`);
export const deactivateCredentialType = (id) => api.post(`/issuer/credential-types/${id}/deactivate/`);

// ─── Issuance Templates ────────────────────────────────────────────────────
export const getTemplates = (params) => api.get('/issuer/templates/', { params });
export const createTemplate = (data) => api.post('/issuer/templates/', data);
export const getTemplate = (id) => api.get(`/issuer/templates/${id}/`);
export const updateTemplate = (id, data) => api.patch(`/issuer/templates/${id}/`, data);
export const previewTemplate = (id, data) => api.post(`/issuer/templates/${id}/preview/`, data);
export const activateTemplate = (id) => api.post(`/issuer/templates/${id}/activate/`);
export const deactivateTemplate = (id) => api.post(`/issuer/templates/${id}/deactivate/`);
export const getTemplateVersions = (id) => api.get(`/issuer/templates/${id}/versions/`);
export const getTemplateApiFieldPreview = (id) => api.get(`/issuer/templates/${id}/api-field-preview/`);

// ─── Issuance Pipeline ─────────────────────────────────────────────────────
export const issueCredential = (data) => api.post('/issuer/issue/', data);
export const bulkIssueCredentials = (formData) =>
  api.post('/issuer/issue/bulk/', formData, { headers: { 'Content-Type': 'multipart/form-data' } });

// ─── Issued Credentials ────────────────────────────────────────────────────
export const getIssuedCredentials = (params) => api.get('/issuer/issued/', { params });
export const getIssuedCredential = (id) => api.get(`/issuer/issued/${id}/`);
export const revokeCredential = (id, data) => api.post(`/issuer/issued/${id}/revoke/`, data);
export const suspendCredential = (id, data) => api.post(`/issuer/issued/${id}/suspend/`, data);
export const reinstateCredential = (id) => api.post(`/issuer/issued/${id}/reinstate/`);

// ─── Pending Credentials (awaiting holder wallet registration) ─────────────
export const getPendingCredentials = (params) => api.get('/issuer/pending-credentials/', { params });
export const cancelPendingCredential = (id) => api.post(`/issuer/pending-credentials/${id}/cancel/`);
export const deliverPendingCredentials = () => api.post('/issuer/pending-credentials/deliver/');

// ─── Credential Requests ───────────────────────────────────────────────────
export const getIssuerRequests = (params) => api.get('/issuer/requests/', { params });
export const getIssuerRequest = (id) => api.get(`/issuer/requests/${id}/`);
export const approveRequest = (id, data) => api.post(`/issuer/requests/${id}/approve/`, data);
export const rejectRequest = (id, data) => api.post(`/issuer/requests/${id}/reject/`, data);
export const bulkApproveRequests = (data) => api.post('/issuer/requests/bulk-approve/', data);
export const bulkRejectRequests = (data) => api.post('/issuer/requests/bulk-reject/', data);

// ─── Dashboard & Analytics ─────────────────────────────────────────────────
export const getIssuerDashboard = () => api.get('/issuer/dashboard/');
export const getIssuerAnalyticsStats = () => api.get('/issuer/analytics/stats/');
export const getIssuerAnalyticsTrends = (params) => api.get('/issuer/analytics/trends/', { params });
export const getIssuerAnalyticsByType = () => api.get('/issuer/analytics/by-type/');
export const getIssuerAnalyticsFailures = () => api.get('/issuer/analytics/failures/');

// ─── Signatories ───────────────────────────────────────────────────────────
export const getSignatories = () => api.get('/issuer/signatories/');
export const createSignatory = (data) => api.post('/issuer/signatories/', data);
export const updateSignatory = (id, data) => api.patch(`/issuer/signatories/${id}/`, data);
export const deleteSignatory = (id) => api.delete(`/issuer/signatories/${id}/`);

// ─── Notifications ─────────────────────────────────────────────────────────
export const getIssuerNotifications = () => api.get('/issuer/notifications/');
export const markNotificationsRead = (data) => api.post('/issuer/notifications/mark-read/', data);

// ─── Legacy (kept for backward compat with existing views) ─────────────────
export const getIssuerProfile = () => api.get('/issuer/profile/');
export const updateIssuerProfile = (data) => api.patch('/issuer/profile/', data);
export const getIssuerSettings = () => api.get('/issuer/settings/');
export const updateIssuerBranding = (data) => api.patch('/issuer/settings/branding/', data);
export const updateIssuerContact = (data) => api.patch('/issuer/settings/contact/', data);
export const getIssuerAuditLog = (params) => api.get('/issuer/settings/audit-log/', { params });

