import { useEffect, useState } from 'react';
import { useForm, useFieldArray } from 'react-hook-form';
import { getApiConfig, saveApiConfig, testApiConfig, getMemberPreview, getIntegrationGuide } from '../../api/issuer';
import Input from '../../components/common/Input';
import Button from '../../components/common/Button';
import { CardSkeleton } from '../../components/common/SkeletonLoader';
import toast from 'react-hot-toast';
import {
  Plug, Plus, Trash2, CheckCircle2, XCircle, Search,
  ArrowRight, ExternalLink, AlertTriangle, Clock, Info,
} from 'lucide-react';

function StatusPill({ status }) {
  const map = {
    success: { label: 'Tested & Working', color: 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300', icon: CheckCircle2 },
    failed: { label: 'Test Failed', color: 'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300', icon: XCircle },
    untested: { label: 'Not Yet Tested', color: 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-300', icon: AlertTriangle },
    not_configured: { label: 'Not Configured', color: 'bg-muted text-muted-foreground', icon: Plug },
  };
  const s = map[status] || map.not_configured;
  const Icon = s.icon;
  return (
    <span className={`inline-flex items-center gap-1.5 text-xs font-medium px-2.5 py-1 rounded-full ${s.color}`}>
      <Icon className="h-3 w-3" />
      {s.label}
    </span>
  );
}

export default function ApiConfigPage() {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [testing, setTesting] = useState(false);
  const [testResult, setTestResult] = useState(null);
  const [testMemberId, setTestMemberId] = useState('');
  const [previewId, setPreviewId] = useState('');
  const [previewLoading, setPreviewLoading] = useState(false);
  const [previewResult, setPreviewResult] = useState(null);
  const [currentStatus, setCurrentStatus] = useState('not_configured');
  const [guideOpen, setGuideOpen] = useState(false);

  const { register, handleSubmit, control, reset, formState: { errors } } = useForm({
    defaultValues: {
      api_base_url: '',
      member_verify_endpoint: '/api/members/verify',
      api_key_header: 'X-API-Key',
      api_key_value: '',
      request_id_field: 'member_id',
      response_eligibility_field: 'is_eligible',
      response_name_field: 'member.full_name',
      field_mappings: [],
    },
  });

  const { fields, append, remove } = useFieldArray({ control, name: 'field_mappings' });

  useEffect(() => {
    getApiConfig()
      .then((r) => {
        if (r.data) {
          const d = r.data;
          reset({
            api_base_url: d.api_base_url || '',
            member_verify_endpoint: d.member_verify_endpoint || '/api/members/verify',
            api_key_header: d.api_key_header || 'X-API-Key',
            api_key_value: '',
            request_id_field: d.request_id_field || 'member_id',
            response_eligibility_field: d.response_eligibility_field || 'is_eligible',
            response_name_field: d.response_name_field || 'member.full_name',
            field_mappings: d.field_mappings || [],
          });
          setCurrentStatus(d.last_test_status || 'untested');
        }
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const onSubmit = async (data) => {
    setSaving(true);
    try {
      const res = await saveApiConfig(data);
      setCurrentStatus(res.data?.last_test_status || 'untested');
      toast.success('API configuration saved');
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to save');
    } finally { setSaving(false); }
  };

  const handleTest = async () => {
    if (!testMemberId.trim()) { toast.error('Enter a test member ID'); return; }
    setTesting(true);
    setTestResult(null);
    try {
      const res = await testApiConfig({ test_member_id: testMemberId.trim() });
      setTestResult(res.data);
      setCurrentStatus(res.data.last_test_status || (res.data.success ? 'success' : 'failed'));
      if (res.data.success) toast.success('Connection test passed!');
      else toast.error('Connection test failed — see details below');
    } catch (err) {
      const errMsg = err.response?.data?.error || 'Connection test failed';
      setTestResult({ success: false, error: errMsg });
      setCurrentStatus('failed');
      toast.error(errMsg);
    } finally { setTesting(false); }
  };

  const handlePreview = async () => {
    if (!previewId.trim()) { toast.error('Enter a member identifier'); return; }
    setPreviewLoading(true);
    setPreviewResult(null);
    try {
      const res = await getMemberPreview({ member_identifier: previewId.trim() });
      setPreviewResult(res.data);
      if (res.data.found) toast.success('Member found!');
      else toast.error('Member not found or not eligible');
    } catch (err) {
      setPreviewResult({ found: false, error: err.response?.data?.error || 'Preview failed' });
    } finally { setPreviewLoading(false); }
  };

  if (loading) return <CardSkeleton />;

  return (
    <div className="space-y-6 max-w-2xl">
      <div className="flex items-start justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground flex items-center gap-2">
            <Plug className="h-6 w-6" /> Member API Configuration
          </h1>
          <p className="text-muted-foreground text-sm mt-1">
            Connect your organization's member database so the platform can verify eligibility before issuing credentials.
          </p>
        </div>
        <StatusPill status={currentStatus} />
      </div>

      {/* How This Works */}
