import { useEffect, useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { getTemplates, getTemplate, bulkIssueCredentials } from '../../api/issuer';
import Select from '../../components/common/Select';
import Button from '../../components/common/Button';
import Table from '../../components/common/Table';
import { CheckCircle, XCircle, Download, UploadCloud, FileText, AlertCircle } from 'lucide-react';
import toast from 'react-hot-toast';

function buildSampleCsv(template) {
  if (!template) {
    return `member_identifier\nNID-1234567890\nNID-0987654321\n`;
  }
  const manualFields = (template.fields || []).filter((f) => f.source === 'manual');
  const headers = ['member_identifier', ...manualFields.map((f) => f.name)];
  const exampleRow = ['NID-1234567890', ...manualFields.map((f) => f.label || f.name || 'value')];
  const exampleRow2 = ['NID-0987654321', ...manualFields.map((f) => f.label || f.name || 'value')];
  return `${headers.join(',')}\n${exampleRow.join(',')}\n${exampleRow2.join(',')}\n`;
}

const FAILURE_REASON_MAP = {
  member_not_eligible: 'Member not found or not eligible in your system',
  api_timeout: 'Member API timed out — please check that your API server is running',
  api_error: 'Member API returned an error',
  invalid_response: 'Member API returned an invalid response',
  api_not_configured: 'Member API is not configured',
  api_unreachable: 'Could not reach your member API',
};

function friendlyReason(reason) {
  if (!reason) return 'Unknown error';
  for (const [key, label] of Object.entries(FAILURE_REASON_MAP)) {
    if (reason.toLowerCase().includes(key)) return label;
  }
  return reason;
}

export default function BulkIssuancePage() {
  const navigate = useNavigate();
  const fileInputRef = useRef(null);
  const [templates, setTemplates] = useState([]);
  const [selectedTemplateId, setSelectedTemplateId] = useState('');
  const [selectedTemplate, setSelectedTemplate] = useState(null);
  const [file, setFile] = useState(null);
  const [issuing, setIssuing] = useState(false);
  const [result, setResult] = useState(null);

  useEffect(() => {
    getTemplates({ is_active: true })
      .then((r) => setTemplates(r.data?.results || r.data || []))
      .catch(() => {});
  }, []);

  useEffect(() => {
    if (!selectedTemplateId) { setSelectedTemplate(null); return; }
    getTemplate(selectedTemplateId)
      .then((r) => setSelectedTemplate(r.data))
      .catch(() => {});
  }, [selectedTemplateId]);

  const downloadSample = () => {
    const csv = buildSampleCsv(selectedTemplate);
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `bulk_issuance_template${selectedTemplate ? `_${selectedTemplate.name.replace(/\s+/g, '_')}` : ''}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleFileChange = (e) => {
    const f = e.target.files?.[0];
    setFile(f || null);
  };

  const handleIssue = async () => {
    if (!selectedTemplateId) { toast.error('Please select a template'); return; }
    if (!file) { toast.error('Please upload a CSV file'); return; }
    setIssuing(true);
    setResult(null);
    const fd = new FormData();
    fd.append('template_id', selectedTemplateId);
    fd.append('csv_file', file);
    try {
      const res = await bulkIssueCredentials(fd);
      setResult(res.data);
      if (res.data.issued > 0) toast.success(`${res.data.issued} credential(s) issued`);
      if ((res.data.failed_count || res.data.failed || 0) > 0) toast.error(`${res.data.failed_count || res.data.failed} failed`);
    } catch (err) {
      toast.error(err.response?.data?.error || err.response?.data?.detail || 'Bulk issuance failed');
    } finally { setIssuing(false); }
  };

  const manualFields = (selectedTemplate?.fields || []).filter((f) => f.source === 'manual');
  const failedCount = result ? (result.failed_count ?? result.failed ?? 0) : 0;

  const failureColumns = [
    { key: 'member_identifier', label: 'Member ID' },
    {
      key: 'reason',
      label: 'Reason',
      render: (v) => (
        <span className="text-xs text-red-500">{friendlyReason(v)}</span>
      ),
    },
  ];

  return (
    <div className="space-y-6 max-w-2xl">
      <div>
        <h1 className="text-2xl font-bold text-foreground">Bulk Issuance</h1>
        <p className="text-muted-foreground text-sm mt-1">
          Issue credentials to multiple members at once via CSV. Every member is verified
          against your organization's member API.
        </p>
      </div>

      <div className="card p-6 space-y-4">
        <h2 className="text-sm font-semibold text-foreground">Step 1 — Select Template</h2>
        <Select
          label="Issuance Template"
          value={selectedTemplateId}
          onChange={(e) => { setSelectedTemplateId(e.target.value); setResult(null); }}
          required
        >
          <option value="">— Choose template —</option>
          {templates.map((t) => (
            <option key={t.id} value={t.id}>{t.name}{t.version ? ` (v${t.version})` : ''}</option>
          ))}
        </Select>

        {selectedTemplate && (
          <div className="rounded-lg bg-muted/40 p-3 text-xs space-y-1 text-muted-foreground">
            <p><strong className="text-foreground">API fields:</strong> {(selectedTemplate.fields || []).filter((f) => f.source === 'member_api').length} (auto-filled from your member API)</p>
            {manualFields.length > 0 && (
              <p><strong className="text-foreground">Manual columns required:</strong>{' '}
                {manualFields.map((f) => <code key={f.name} className="bg-muted px-1 rounded mx-0.5">{f.name}</code>)}
              </p>
            )}
          </div>
        )}
      </div>

      <div className="card p-6 space-y-4">
        <div className="flex items-center justify-between">
          <h2 className="text-sm font-semibold text-foreground">Step 2 — Upload CSV</h2>
          <Button type="button" variant="ghost" size="sm" onClick={downloadSample}>
            <Download className="h-4 w-4 mr-1" />
            Download Sample{selectedTemplate ? ` (${selectedTemplate.name})` : ''}
          </Button>
        </div>

        <div
          className={`border-2 border-dashed rounded-lg p-6 text-center cursor-pointer transition-colors ${
            file
              ? 'border-green-300 bg-green-50 dark:bg-green-900/10'
              : 'border-border hover:border-primary/50'
          }`}
          onClick={() => fileInputRef.current?.click()}
        >
          <input
            ref={fileInputRef}
            type="file"
            accept=".csv"
            className="hidden"
            onChange={handleFileChange}
          />
          {file ? (
            <div className="flex items-center justify-center gap-2 text-green-700 dark:text-green-300">
              <FileText className="h-5 w-5" />
              <div className="text-left">
                <p className="text-sm font-medium">{file.name}</p>
                <p className="text-xs opacity-70">{(file.size / 1024).toFixed(1)} KB</p>
              </div>
              <button
                onClick={(e) => { e.stopPropagation(); setFile(null); if (fileInputRef.current) fileInputRef.current.value = ''; }}
                className="ml-2 text-red-500 hover:text-red-700 text-xs"
              >
                Remove
              </button>
            </div>
          ) : (
            <div className="text-muted-foreground">
              <UploadCloud className="h-8 w-8 mx-auto mb-2 opacity-40" />
              <p className="text-sm">Click to choose a CSV file</p>
              <p className="text-xs mt-1 opacity-70">Must include a <code className="bg-muted px-1 rounded">member_identifier</code> column</p>
            </div>
          )}
        </div>

        <div className="flex gap-3 pt-2">
          <Button
            onClick={handleIssue}
            isLoading={issuing}
            disabled={!selectedTemplateId || !file}
            className="flex-1"
          >
            <UploadCloud className="h-4 w-4 mr-2" />
            {issuing ? 'Issuing...' : 'Issue All'}
          </Button>
        </div>
      </div>

      {result && (
        <div className="space-y-4">
          <div className="grid grid-cols-3 gap-4">
            {[
              { label: 'Total Rows', value: result.total, color: 'text-foreground' },
              { label: 'Issued', value: result.issued, color: 'text-green-600' },
              { label: 'Failed', value: failedCount, color: failedCount > 0 ? 'text-red-500' : 'text-muted-foreground' },
            ].map((s) => (
              <div key={s.label} className="card p-4 text-center">
                <p className={`text-2xl font-bold ${s.color}`}>{s.value ?? 0}</p>
                <p className="text-xs text-muted-foreground mt-1">{s.label}</p>
              </div>
            ))}
          </div>

          {result.failures?.length > 0 && (
            <div className="card p-4 space-y-3">
              <div className="flex items-center gap-2">
                <AlertCircle className="h-4 w-4 text-red-500" />
                <h3 className="text-sm font-semibold text-foreground">Failed Rows</h3>
              </div>
              <Table
                columns={failureColumns}
                data={result.failures}
                emptyMessage="No failures"
              />
            </div>
          )}

          {result.issued > 0 && (
            <Button variant="outline" onClick={() => navigate('/issuer/issued')} className="w-full">
              View Issued Credentials →
            </Button>
          )}
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  getPendingRegistration, getRegistrationDocuments,
  approveRegistration, rejectRegistration,
} from '../../api/admin';
import Button from '../../components/common/Button';
import { StatusBadge } from '../../components/common/Badge';
import { CardSkeleton } from '../../components/common/SkeletonLoader';
import { formatDate } from '../../utils/formatDate';
import { ArrowLeft, CheckCircle2, XCircle, FileText, Download, Building2 } from 'lucide-react';
import toast from 'react-hot-toast';

export default function OrganizationReviewPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [reg, setReg] = useState(null);
  const [docs, setDocs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [acting, setActing] = useState(null);
  const [rejectReason, setRejectReason] = useState('');
  const [showRejectForm, setShowRejectForm] = useState(false);

  useEffect(() => {
    Promise.all([
      getPendingRegistration(id),
      getRegistrationDocuments(id),
    ]).then(([r, d]) => {
      setReg(r.data);
      setDocs(d.data || []);
    }).catch(() => toast.error('Failed to load registration'))
      .finally(() => setLoading(false));
  }, [id]);

  const handleApprove = async () => {
    setActing('approve');
    try {
      await approveRegistration(id);
      toast.success('Organization approved and account created');
      navigate('/admin/organizations?tab=pending');
    } catch (err) {
      toast.error(err.response?.data?.error || 'Approval failed');
    } finally { setActing(null); }
  };

  const handleReject = async () => {
    if (!rejectReason.trim()) { toast.error('Rejection reason is required'); return; }
    setActing('reject');
    try {
      await rejectRegistration(id, { reason: rejectReason });
      toast.success('Registration rejected');
      navigate('/admin/organizations?tab=pending');
    } catch (err) {
      toast.error(err.response?.data?.error || 'Rejection failed');
    } finally { setActing(null); }
  };

  if (loading) return <CardSkeleton />;
  if (!reg) return <div className="text-muted-foreground">Registration not found.</div>;

  const isAlreadyDecided = reg.status === 'approved' || reg.status === 'rejected';

  return (
    <div className="space-y-6 max-w-3xl">
      <div className="flex items-center gap-3">
        <Button variant="ghost" size="sm" onClick={() => navigate('/admin/organizations')}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <div className="flex-1">
          <div className="flex items-center gap-3">
            <h1 className="text-2xl font-bold text-foreground">{reg.organization_name}</h1>
            <StatusBadge status={reg.status} />
          </div>
          <p className="text-sm text-muted-foreground mt-0.5">
            Submitted {formatDate(reg.submitted_at)} · {reg.organization_type || 'No type'}
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Organization Info */}
        <div className="card p-5 space-y-3">
          <div className="flex items-center gap-2 mb-2">
            <Building2 className="h-4 w-4 text-muted-foreground" />
            <h2 className="text-sm font-semibold text-foreground">Organization</h2>
          </div>
          {[
            ['Name', reg.organization_name],
            ['Type', reg.organization_type],
            ['Email', reg.email],
            ['Phone', reg.phone],
            ['Website', reg.website],
            ['Address', reg.address],
          ].map(([label, val]) => val ? (
            <div key={label} className="flex gap-2 text-sm">
              <span className="text-muted-foreground w-20 flex-shrink-0">{label}</span>
              <span className="text-foreground break-all">{val}</span>
            </div>
          ) : null)}
        </div>

        {/* Contact & Use Case */}
        <div className="card p-5 space-y-3">
          <h2 className="text-sm font-semibold text-foreground">Contact & Use Case</h2>
          {[
            ['Contact', reg.contact_person_name],
            ['Contact Email', reg.contact_person_email],
          ].map(([label, val]) => val ? (
            <div key={label} className="flex gap-2 text-sm">
              <span className="text-muted-foreground w-28 flex-shrink-0">{label}</span>
              <span className="text-foreground">{val}</span>
            </div>
          ) : null)}
          {reg.use_case_description && (
            <div>
              <p className="text-xs text-muted-foreground mb-1">Use Case</p>
              <p className="text-sm text-foreground">{reg.use_case_description}</p>
            </div>
          )}
          {reg.intended_credential_types?.length > 0 && (
            <div>
              <p className="text-xs text-muted-foreground mb-1">Intended Credential Types</p>
              <div className="flex flex-wrap gap-1">
                {reg.intended_credential_types.map((t, i) => (
                  <span key={i} className="text-xs bg-muted px-2 py-0.5 rounded">{t}</span>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Documents */}
      <div className="card p-5 space-y-3">
        <h2 className="text-sm font-semibold text-foreground flex items-center gap-2">
          <FileText className="h-4 w-4" />
          Documents ({docs.length})
        </h2>
        {docs.length === 0 ? (
          <p className="text-sm text-muted-foreground italic">No documents uploaded.</p>
        ) : (
          <div className="space-y-2">
            {docs.map((doc) => (
              <div key={doc.id} className="flex items-center justify-between p-2 rounded border border-border">
                <div className="flex items-center gap-2">
                  <FileText className="h-4 w-4 text-muted-foreground" />
                  <div>
                    <p className="text-sm font-medium text-foreground">{doc.document_type_display}</p>
                    <p className="text-xs text-muted-foreground">{doc.file_name} · {formatDate(doc.uploaded_at)}</p>
                  </div>
                </div>
                {doc.download_url && (
                  <a href={doc.download_url} target="_blank" rel="noopener noreferrer">
                    <Button variant="ghost" size="sm">
                      <Download className="h-4 w-4" />
                    </Button>
                  </a>
                )}
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Rejection reason if rejected */}
      {reg.status === 'rejected' && reg.rejection_reason && (
        <div className="card p-4 border-red-200 dark:border-red-800 bg-red-50/50 dark:bg-red-900/10">
          <p className="text-sm font-medium text-red-800 dark:text-red-200 mb-1">Rejection Reason</p>
          <p className="text-sm text-red-700 dark:text-red-300">{reg.rejection_reason}</p>
          <p className="text-xs text-muted-foreground mt-1">Reviewed {formatDate(reg.reviewed_at)}</p>
        </div>
      )}

      {/* Action Buttons */}
      {!isAlreadyDecided && (
        <div className="card p-5 space-y-4">
          <h2 className="text-sm font-semibold text-foreground">Review Decision</h2>

          {!showRejectForm ? (
            <div className="flex gap-3">
              <Button
                onClick={handleApprove}
                isLoading={acting === 'approve'}
                disabled={!!acting}
                className="flex-1 bg-green-600 hover:bg-green-700 text-white"
              >
                <CheckCircle2 className="h-4 w-4 mr-2" />
                Approve & Create Account
              </Button>
              <Button
                variant="outline"
                onClick={() => setShowRejectForm(true)}
                disabled={!!acting}
                className="flex-1 border-red-300 text-red-600 hover:bg-red-50"
              >
                <XCircle className="h-4 w-4 mr-2" />
                Reject
              </Button>
            </div>
          ) : (
            <div className="space-y-3">
              <div>
                <label className="text-sm font-medium text-foreground block mb-1">
                  Rejection Reason <span className="text-red-500">*</span>
                </label>
                <textarea
                  value={rejectReason}
                  onChange={(e) => setRejectReason(e.target.value)}
                  rows={3}
                  className="w-full rounded-md border border-border bg-background px-3 py-2 text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-primary/50"
                  placeholder="Explain why this registration is being rejected..."
                />
              </div>
              <div className="flex gap-2">
                <Button
                  onClick={handleReject}
                  isLoading={acting === 'reject'}
                  disabled={!!acting || !rejectReason.trim()}
                  className="flex-1 bg-red-600 hover:bg-red-700 text-white"
                >
                  Confirm Rejection
                </Button>
                <Button
                  variant="outline"
                  onClick={() => setShowRejectForm(false)}
                  disabled={!!acting}
                >
                  Cancel
                </Button>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

