import { useEffect, useState } from 'react';
import { getPendingCredentials, cancelPendingCredential, deliverPendingCredentials } from '../../api/issuer';
import Button from '../../components/common/Button';
import Table from '../../components/common/Table';
import Pagination from '../../components/common/Pagination';
import { StatusBadge } from '../../components/common/Badge';
import { formatDate } from '../../utils/formatDate';
import { Users, RefreshCw, XCircle, Info } from 'lucide-react';
import toast from 'react-hot-toast';

export default function PendingCredentialsPage() {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [page, setPage] = useState(1);
  const [total, setTotal] = useState(0);
  const [delivering, setDelivering] = useState(false);
  const [cancelling, setCancelling] = useState({});
  const PAGE_SIZE = 20;

  const load = () => {
    setLoading(true);
    getPendingCredentials({ status: 'pending_holder_registration', page, page_size: PAGE_SIZE })
      .then((r) => {
        setItems(r.data?.results || []);
        setTotal(r.data?.count || 0);
      })
      .catch(() => toast.error('Failed to load pending credentials'))
      .finally(() => setLoading(false));
  };

  useEffect(load, [page]);

  const handleDeliver = async () => {
    setDelivering(true);
    try {
      const r = await deliverPendingCredentials();
      toast.success(`Delivered: ${r.data.delivered}, Skipped (not yet registered): ${r.data.skipped}`);
      load();
    } catch { toast.error('Delivery failed'); }
    finally { setDelivering(false); }
  };

  const handleCancel = async (id) => {
    setCancelling((c) => ({ ...c, [id]: true }));
    try {
      await cancelPendingCredential(id);
      toast.success('Pending credential cancelled');
      load();
    } catch (err) {
      toast.error(err.response?.data?.error || 'Cancel failed');
    } finally { setCancelling((c) => ({ ...c, [id]: false })); }
  };

  const columns = [
    { key: 'member_identifier', label: 'Member ID' },
    { key: 'member_name', label: 'Member Name', render: (v) => v || '—' },
    { key: 'template', label: 'Template', render: (v) => v || '—' },
    { key: 'status', label: 'Status', render: (v) => <StatusBadge status={v} /> },
    { key: 'assembled_at', label: 'Prepared', render: (v) => formatDate(v) },
    {
      key: 'id', label: 'Actions',
      render: (id) => (
        <Button
          size="sm" variant="outline"
          className="text-red-500 border-red-200"
          isLoading={!!cancelling[id]}
          onClick={() => handleCancel(id)}
        >
          <XCircle className="h-3.5 w-3.5 mr-1" /> Cancel
        </Button>
      ),
    },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-start justify-between">
        <div>
          <h1 className="text-2xl font-bold text-foreground flex items-center gap-2">
            <Users className="h-6 w-6" /> Pending Delivery
          </h1>
          <p className="text-sm text-muted-foreground mt-1">
            Credentials ready to issue but the recipient has not yet registered a wallet.
            They will be delivered automatically once the holder creates an account and verifies their identity.
          </p>
        </div>
        <Button variant="outline" onClick={handleDeliver} isLoading={delivering}>
          <RefreshCw className="h-4 w-4 mr-2" /> Deliver Now
        </Button>
      </div>

      <div className="card border-blue-200 dark:border-blue-800 bg-blue-50/50 dark:bg-blue-900/10 p-4 flex gap-3 text-sm text-blue-700 dark:text-blue-300">
        <Info className="h-4 w-4 mt-0.5 flex-shrink-0" />
        <p>
          <strong>How this works:</strong> When you issue a credential to a member who has not yet registered a wallet,
          the credential is held here. As soon as the member signs up and verifies their national ID,
          the credential is automatically delivered to their wallet.
          Use <em>Deliver Now</em> to manually attempt delivery for any already-registered holders.
        </p>
      </div>

      <div className="card">
        <div className="p-4 border-b border-border flex items-center justify-between">
          <p className="text-sm text-muted-foreground">
            {total} pending credential{total !== 1 ? 's' : ''}
          </p>
        </div>
        <Table
          columns={columns}
          data={items}
          loading={loading}
          emptyMessage="No pending credentials — all issued credentials have been delivered."
        />
        <div className="p-4">
          <Pagination page={page} totalPages={Math.ceil(total / PAGE_SIZE)} onPageChange={setPage} />
        </div>
      </div>
    </div>
  );
}

"""
Admin Registration Review Views
GET  /api/admin/organizations/pending/            — list pending IssuerRegistrations
GET  /api/admin/organizations/pending/{id}/documents/ — get registration + documents
POST /api/admin/organizations/{id}/approve/       — approve registration → create org/user
POST /api/admin/organizations/{id}/reject/        — reject with reason
"""
from __future__ import annotations
import logging
import secrets
import string

from django.contrib.auth import get_user_model
from django.db import transaction
from rest_framework.permissions import IsAuthenticated
from rest_framework.response import Response
from rest_framework.views import APIView

from common.permissions import IsAdminUser

logger = logging.getLogger(__name__)
User = get_user_model()


def _get_reg_model():
    try:
        from organizations.models import IssuerRegistration
        return IssuerRegistration
    except ImportError:
        return None


def _get_doc_model():
    try:
        from organizations.models import IssuerRegDocument
        return IssuerRegDocument
    except ImportError:
        return None


def _reg_data(reg) -> dict:
    return {
        'id': str(reg.id),
        'organization_name': reg.organization_name,
        'organization_type': getattr(reg, 'organization_type', None) or getattr(reg, 'org_type', None),
        'email': reg.email,
        'phone': getattr(reg, 'phone', None),
        'website': getattr(reg, 'website', None),
        'address': getattr(reg, 'address', None),
        'contact_person_name': getattr(reg, 'contact_person_name', None),
        'contact_person_email': getattr(reg, 'contact_person_email', None),
        'use_case_description': getattr(reg, 'use_case_description', None),
        'intended_credential_types': getattr(reg, 'intended_credential_types', []) or [],
        'status': reg.status,
        'rejection_reason': getattr(reg, 'rejection_reason', None),
        'submitted_at': reg.submitted_at.isoformat() if hasattr(reg, 'submitted_at') and reg.submitted_at else None,
        'reviewed_at': reg.reviewed_at.isoformat() if hasattr(reg, 'reviewed_at') and reg.reviewed_at else None,
    }


def _doc_data(doc) -> dict:
    return {
        'id': str(doc.id),
        'document_type': doc.document_type,
        'document_type_display': getattr(doc, 'get_document_type_display', lambda: doc.document_type)(),
        'file_name': getattr(doc, 'file_name', None) or str(getattr(doc, 'file', '')).split('/')[-1],
        'uploaded_at': doc.uploaded_at.isoformat() if hasattr(doc, 'uploaded_at') and doc.uploaded_at else None,
        'download_url': doc.file.url if hasattr(doc, 'file') and doc.file else None,
    }


class PendingRegistrationsView(APIView):
    """GET /api/admin/organizations/pending/"""
    permission_classes = [IsAuthenticated, IsAdminUser]

    def get(self, request):
        Reg = _get_reg_model()
        if Reg is None:
            return Response({'error': 'IssuerRegistration model not available'}, status=503)

        status_filter = request.query_params.get('status', 'pending')
        search = request.query_params.get('search', '')

        qs = Reg.objects.all().order_by('-submitted_at')
        if status_filter:
            qs = qs.filter(status=status_filter)
        if search:
            qs = qs.filter(organization_name__icontains=search)

        page_size = int(request.query_params.get('page_size', 20))
        page = int(request.query_params.get('page', 1))
        total = qs.count()
        offset = (page - 1) * page_size
        items = qs[offset:offset + page_size]

        return Response({
            'count': total,
            'results': [_reg_data(r) for r in items],
        })


class RegistrationDocumentsView(APIView):
    """GET /api/admin/organizations/pending/{registration_id}/documents/"""
    permission_classes = [IsAuthenticated, IsAdminUser]

    def get(self, request, registration_id):
        Reg = _get_reg_model()
        Doc = _get_doc_model()
        if Reg is None:
            return Response({'error': 'IssuerRegistration model not available'}, status=503)

        try:
            reg = Reg.objects.get(id=registration_id)
        except Reg.DoesNotExist:
            return Response({'error': 'Registration not found'}, status=404)

        docs = []
        if Doc is not None:
            try:
                docs = Doc.objects.filter(registration=reg)
            except Exception:
                docs = []

        reg_data = _reg_data(reg)
        reg_data['documents'] = [_doc_data(d) for d in docs]

        return Response(reg_data)


class ApproveRegistrationView(APIView):
    """POST /api/admin/organizations/{registration_id}/approve/"""
    permission_classes = [IsAuthenticated, IsAdminUser]

    @transaction.atomic
    def post(self, request, registration_id):
        Reg = _get_reg_model()
        if Reg is None:
            return Response({'error': 'IssuerRegistration model not available'}, status=503)

        try:
            reg = Reg.objects.select_for_update().get(id=registration_id)
        except Reg.DoesNotExist:
            return Response({'error': 'Registration not found'}, status=404)

        if reg.status == 'approved':
            return Response({'error': 'Registration already approved'}, status=400)

        try:
            org, user = _create_org_and_user(reg, request.user)
        except Exception as exc:
            logger.exception('Failed to create org/user for registration %s: %s', registration_id, exc)
            return Response({'error': f'Failed to create organization account: {exc}'}, status=500)

        # Update registration status
        reg.status = 'approved'
        if hasattr(reg, 'reviewed_by'):
            reg.reviewed_by = request.user
        if hasattr(reg, 'reviewed_at'):
            from django.utils import timezone
            reg.reviewed_at = timezone.now()
        reg.save()

        return Response({
            'status': 'approved',
            'organization_id': str(org.id),
            'message': f'Organization "{org.name}" approved. Login credentials emailed to {reg.email}.',
        })


def _create_org_and_user(reg, admin_user):
    from organizations.models import Organization, OrganizationMember
    from django.utils import timezone

    # Create or get the organization
    org, _ = Organization.objects.get_or_create(
        name=reg.organization_name,
        defaults={
            'org_type': getattr(reg, 'organization_type', None) or getattr(reg, 'org_type', 'educational'),
            'email': reg.email,
            'website': getattr(reg, 'website', ''),
            'phone': getattr(reg, 'phone', ''),
            'status': 'active',
        },
    )

    # Create issuer user (or get existing)
    contact_email = getattr(reg, 'contact_person_email', None) or reg.email
    existing = User.objects.filter(email=contact_email).first()
    if existing:
        user = existing
    else:
        temp_password = _generate_temp_password()
        user = User.objects.create_user(
            email=contact_email,
            username=contact_email,
            first_name=(getattr(reg, 'contact_person_name', '') or '').split(' ')[0],
            last_name=' '.join((getattr(reg, 'contact_person_name', '') or '').split(' ')[1:]),
            password=temp_password,
            role='issuer_admin',
        )
        # Log temp password — in production send via email
        logger.info('Created issuer user %s with temp password for org %s', contact_email, org.name)

    # Add user as org manager
    OrganizationMember.objects.get_or_create(
        user=user, organization=org,
        defaults={'role_in_org': 'manager', 'is_active': True},
    )

    return org, user


def _generate_temp_password(length: int = 16) -> str:
    alphabet = string.ascii_letters + string.digits + '!@#$'
    return ''.join(secrets.choice(alphabet) for _ in range(length))


class RejectRegistrationView(APIView):
    """POST /api/admin/organizations/{registration_id}/reject/"""
    permission_classes = [IsAuthenticated, IsAdminUser]

    def post(self, request, registration_id):
        Reg = _get_reg_model()
        if Reg is None:
            return Response({'error': 'IssuerRegistration model not available'}, status=503)

        try:
            reg = Reg.objects.get(id=registration_id)
        except Reg.DoesNotExist:
            return Response({'error': 'Registration not found'}, status=404)

        reason = request.data.get('reason', '').strip()
        if not reason:
            return Response({'error': 'Rejection reason is required'}, status=400)

        reg.status = 'rejected'
        if hasattr(reg, 'rejection_reason'):
            reg.rejection_reason = reason
        if hasattr(reg, 'reviewed_by'):
            reg.reviewed_by = request.user
        if hasattr(reg, 'reviewed_at'):
            from django.utils import timezone
            reg.reviewed_at = timezone.now()
        reg.save()

        return Response({'status': 'rejected', 'reason': reason})

